INSERT IGNORE INTO `questions` (`id`, `project_id`, `question_text`, `question_image`, `type`, `choices`, `correct_answer`, `explanation`, `score_weight`, `category`, `difficulty`, `order_num`, `is_active`, `created_by`, `created_at`) VALUES ('6', '1', 'SDG Goals คือ', NULL, 'multiple_choice', '[{\"key\": \"a\", \"text\": \"เป้าหมายการพัฒนาที่ยั่งยืน\"}, {\"key\": \"b\", \"text\": \"เป้าหมายการพัฒนาลดจำนวนผู้ขาดสารอาหาร\"}, {\"key\": \"c\", \"text\": \"เป้าหมายความเท่าเทียมทางเพศและการเพิ่มอำนาจสตรี\"}, {\"key\": \"d\", \"text\": \"เป้าหมายส่งเสริมความเป็นหุ้นส่วนทั่วโลกสำหรับการพัฒนา\"}]', 'a', NULL, '1.00', NULL, 'medium', '0', '1', '1', '2026-05-11 15:38:46');
INSERT IGNORE INTO `questions` (`id`, `project_id`, `question_text`, `question_image`, `type`, `choices`, `correct_answer`, `explanation`, `score_weight`, `category`, `difficulty`, `order_num`, `is_active`, `created_by`, `created_at`) VALUES ('7', '1', 'THE SDG Impact Rankings 2025 มหาวิทยาลัยราชภัฏร้อยเอ็ดได้รับการจัดอันดับเป้าหมายใดที่ดีที่สุด', NULL, 'multiple_choice', '[{\"key\": \"a\", \"text\": \"เป้าหมายที่ 1: ขจัดความยากจน (No Poverty)\"}, {\"key\": \"b\", \"text\": \"เป้าหมายที่ 3: การมีสุขภาพและความเป็นอยู่ที่ดี (Good Health and Well-being)\"}, {\"key\": \"c\", \"text\": \"เป้าหมายที่ 4: การศึกษาที่มีคุณภาพ (Quality Education)\"}, {\"key\": \"d\", \"text\": \"เป้าหมายที่ 15: ระบบนิเวศบนบก (Life on Land)\"}]', 'c', NULL, '1.00', NULL, 'medium', '0', '1', '1', '2026-05-11 15:39:05');
INSERT IGNORE INTO `questions` (`id`, `project_id`, `question_text`, `question_image`, `type`, `choices`, `correct_answer`, `explanation`, `score_weight`, `category`, `difficulty`, `order_num`, `is_active`, `created_by`, `created_at`) VALUES ('8', '1', 'มหาวิทยาลัยราชภัฏร้อยเอ็ดมีวิสัยทัศน์ (Vision) ว่าอย่างไร', NULL, 'multiple_choice', '[{\"key\": \"a\", \"text\": \"มหาวิทยาลัยสร้างปัญญาและนวัตกรรมชุมชน สู่สากล อย่างยั่งยืน\"}, {\"key\": \"b\", \"text\": \"เป็นมหาวิทยาลัยแห่งการเรียนรู้ วิจัย และสร้างนวัตกรรมระดับโลก เพื่อการพัฒนาอย่างยั่งยืน\"}, {\"key\": \"c\", \"text\": \"เป็นสถาบันอุดมศึกษาชั้นนําเพื่อการพัฒนาคุณภาพชีวิตของท้องถิ่นอย่างยั่งยืน\"}, {\"key\": \"d\", \"text\": \"มุ่งสู่การเป็นมหาวิทยาลัยชั้นนำในระดับชาติหรือนานาชาติ\"}]', 'c', NULL, '1.00', NULL, 'medium', '0', '1', '1', '2026-05-11 15:39:27');
INSERT IGNORE INTO `questions` (`id`, `project_id`, `question_text`, `question_image`, `type`, `choices`, `correct_answer`, `explanation`, `score_weight`, `category`, `difficulty`, `order_num`, `is_active`, `created_by`, `created_at`) VALUES ('9', '1', 'นักศึกษาท่านหนึ่ง บอกพนักงานขายให้ใส่ของที่ซื้อทั้งหมดในถุงพลาสติกใบเดียว  การกระทำนี้จัดว่าเป็นการลดปริมาณขยะวิธีใด', NULL, 'multiple_choice', '[{\"key\": \"a\", \"text\": \"Reduce\"}, {\"key\": \"b\", \"text\": \"Repair\"}, {\"key\": \"c\", \"text\": \"Reuse\"}, {\"key\": \"d\", \"text\": \"Return\"}]', 'a', NULL, '1.00', NULL, 'medium', '0', '1', '1', '2026-05-11 15:39:50');
